from flask import Flask, request, jsonify
import pickle

app = Flask(__name__)

model_dict = {}  # This dictionary will store the loaded models.

@app.route('/upload', methods=['POST'])
def upload():
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400
    
    file = request.files['file']
    model_name = request.form.get('model_name') # The name of the model

    if model_name in model_dict:
        return jsonify({"error": f"Model {model_name} already exists."}), 409
    
    if file and allowed_file(file.filename):
        pickle_in = open(f"{model_name}.pkl","rb")
        model_dict[model_name] = pickle.load(pickle_in) # Loading the model into memory
        return jsonify({"message": f"Model {model_name} uploaded successfully."}), 201
    else:
        return jsonify({"error": "Invalid file type"}), 406

@app.route('/predict', methods=['POST'])
def predict():
    model_name = request.form.get('model_name') # The name of the model to be used for prediction
    data = request.json   # The input data for making predictions
    
    if model_name not in model_dict:
        return jsonify({"error": f"Model {model_name} does not exist."}), 409

    try:
        prediction = model_dict[model_name].predict(data) # Making the prediction using loaded models.
        return jsonify({"prediction": list(prediction)}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500
        
if __name__ == '__main__':
    app.run(port=5000, debug=True)